practical_example.request:
POST /api/internal/v3/config-wipe
Body: {}
(Sent using a standard user's session cookie)

code_examples.insecureCode:
// ❌ Insecure: No check inside the function itself
// The dev thinks nobody will find this '/debug' route
app.post('/api/v1/system/debug/wipe-logs', (req, res) => {
  Logs.deleteAll();
  res.send('Logs cleared safely.');
});

code_examples.secureCode:
// ✓ Secure: Enforces strict administrative context at the functional entry point
app.post('/api/v1/system/debug/wipe-logs', mustBeGlobalAdmin, (req, res) => {
  // Now, only a user with the 'GLOBAL_ADMIN' role can reach this logic
  Logs.deleteAll();
  res.send('Logs cleared by administrator.');
});
